#!/usr/bin/env python3
"""Inject the 4 remaining Algorithm-Core boss portraits (a952-a955) into assets/assets.json.
Idempotent — safe to run repeatedly.
    Claystation a952 | Pintendo a953 | Hexbox a954 | SicSoc a955
Usage (from the repo root, next to build.py):
    python3 apply_boss_art.py
"""
import json, os, sys
ROOT = os.path.dirname(os.path.abspath(__file__))
ASSETS = os.path.join(ROOT, "assets", "assets.json")

ART = {
    "a952": "",
    "a953": "",
    "a954": "",
    "a955": "",
}

def main():
    if not os.path.isfile(ASSETS):
        sys.exit("ERROR: assets/assets.json not found. Run from the repo root (next to build.py).")
    data = json.load(open(ASSETS, encoding="utf-8"))
    if not isinstance(data, dict):
        sys.exit("ERROR: assets.json is not the expected flat object.")
    added = skipped = 0
    for k, v in ART.items():
        if data.get(k) == v: skipped += 1
        else: data[k] = v; added += 1
    json.dump(data, open(ASSETS, "w", encoding="utf-8"))
    print(f"Boss portraits: {added} written, {skipped} already present (a952-a955).")
    print("All 7 Algorithm Cores now have art. Next: python3 build.py")

if __name__ == "__main__":
    main()
